SELECT ID, USERNAME, GROUP_NAME, API_KEY, REFRESH_TOKEN,
       IS_DEL, DELETED_AT, CREATED_AT, UPDATED_AT
FROM TBL_USER
WHERE USERNAME = #{username}
  AND REFRESH_TOKEN = #{refreshToken}
  AND IS_DEL = 'N'

SELECT COUNT(*)
FROM TBL_REDIRECTION_HISTORY
WHERE SHORT_URL_ID = #{shortUrlId}
